mapper.select:
SELECT g.id, g.name, g.description, g.price, g.image_url, g.status, g.created_at, g.updated_at, (s.total_stock - s.locked_stock - s.sold_count) AS available_stock FROM t_goods g LEFT JOIN t_stock s ON g.id = s.goods_id WHERE g.status = 1
AND g.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY g.id DESC LIMIT #{offset}, #{size}
